const item = $input.item.json;
if (item.gate_opt_out_active) { console.log('[GATE] OPT-OUT BLOQUEADO para ' + item.brand_id); return { json: { brand_id: item.brand_id, reply_type: item.reply_type, reply_text: item.reply_text, classification: item.classification, blocked_by_compliance: true, gate_opt_out_active: true, slack_message: null, whatsapp_message: null, action: 'BLOQUEADO' } }; }
const intentScore = Number.isFinite(Number(item.classification.intent_score)) ? Number(item.classification.intent_score) : 0;
const action = ['agendar', 'nurture', 'descartar'].includes(String(item.classification.suggested_action || '').trim().toLowerCase()) ? String(item.classification.suggested_action).trim().toLowerCase() : (intentScore >= 70 ? 'agendar' : intentScore >= 40 ? 'nurture' : 'descartar');
let slack_msg = '';
let wa_msg = '';
if (action === 'agendar') {
  slack_msg = '[LEAD CALIFICADO] ' + item.brand_id + ' | ' + item.category + '
Intent: ' + item.classification.intent_score + '/100 | Score: ' + item.classification.final_score + '/100
Reply: ' + item.reply_text + '
Accion: AGENDAR';
  wa_msg = 'Hola, un especialista de Addi Marketplace se contactara en las proximas horas.';
} else if (action === 'nurture') {
  slack_msg = '[NURTURE] ' + item.brand_id + ' | ' + item.category + '
Intent: ' + item.classification.intent_score + '/100
Reply: ' + item.reply_text + '
Accion: NURTURE';
  wa_msg = null;
} else {
  slack_msg = '[DESCARTADO] ' + item.brand_id + '
Intent: ' + item.classification.intent_score + '/100
Reply: ' + item.reply_text;
  wa_msg = null;
}
return { json: { brand_id: item.brand_id, reply_type: item.reply_type, reply_text: item.reply_text, classification: item.classification, blocked_by_compliance: false, gate_opt_out_active: false, slack_message: slack_msg, whatsapp_message: wa_msg, action: action } };

const item = $input.item.json;
if (item.blocked_by_compliance) { console.log('[COMPLIANCE] WhatsApp BLOQUEADO'); return { json: { brand_id: item.brand_id, action: item.action, whatsapp_sent: false, whatsapp_blocked: true } }; }
if (item.whatsapp_message) { console.log('[WHATSAPP SIM]'); return { json: { brand_id: item.brand_id, action: item.action, whatsapp_sent: true, whatsapp_blocked: false } }; } else { console.log('[WHATSAPP] Omitido'); return { json: { brand_id: item.brand_id, action: item.action, whatsapp_sent: false, whatsapp_blocked: false } }; }

const item = $input.item.json;
const log = { timestamp: new Date().toISOString(), brand_id: item.brand_id, reply_type: item.reply_type, intent_score: item.classification.intent_score, action: item.classification.suggested_action, slack_sent: !item.whatsapp_blocked, whatsapp_blocked: item.whatsapp_blocked, result: item.whatsapp_blocked ? 'PASS - OPT-OUT BLOQUEADO' : 'PASS' };
console.log(JSON.stringify(log, null, 2));
return { json: log };
